class SecureQueryExecutor(spark: SparkSession) {
  
  private val allowedOperations = Set("SELECT", "WITH", "SHOW", "DESCRIBE", "EXPLAIN")
  private val blockedPatterns = List(
    "(?i)\\bDROP\\b",
    "(?i)\\bDELETE\\b",
    "(?i)\\bTRUNCATE\\b",
    "(?i)\\bINSERT\\b",
    "(?i)\\bUPDATE\\b",
    "(?i)\\bCREATE\\b",
    "(?i)\\bALTER\\b",
    "(?i)\\bMERGE\\b",
    "(?i)\\bGRANT\\b",
    "(?i)\\bREVOKE\\b"
  )
  
  private val allowedTables = Set(
    "sales_data",
    "customer_data",
    "product_catalog",
    "web_analytics",
    "transaction_logs",
    "user_events"
  )
  
  def validateQuery(query: String): Either[String, String] = {
    val trimmedQuery = query.trim
    
    if (trimmedQuery.isEmpty) {
      return Left("Query cannot be empty")
    }
    
    for (pattern <- blockedPatterns) {
      if (trimmedQuery.matches(s".*$pattern.*")) {
        return Left(s"Query contains forbidden operation: ${pattern.replaceAll("\\(\\?i\\)\\\\\\\\b", "").replaceAll("\\\\\\\\b", "")}")
      }
