    val firstWord = trimmedQuery.split("\\s+")(0).toUpperCase
    if (!allowedOperations.contains(firstWord)) {
      return Left(s"Operation not allowed: $firstWord. Only ${allowedOperations.mkString(", ")} are permitted")
    }
    
