      val parsed = spark.sessionState.sqlParser.parsePlan(trimmedQuery)
      validateLogicalPlan(parsed)
    } match {
      case Success(_) => Right(trimmedQuery)
      case Failure(e: ParseException) => Left(s"SQL parse error: ${e.getMessage}")
      case Failure(e) => Left(s"Query validation error: ${e.getMessage}")
    }
  }
  
  private def validateLogicalPlan(plan: LogicalPlan): Unit = {
    plan.foreach {
      case UnresolvedRelation(tableIdentifier, _, _) =>
        val tableName = tableIdentifier.table.toLowerCase
