object DataLakeAnalyticsApp {
  
  def initializeSpark(appName: String): SparkSession = {
    SparkSession.builder()
      .appName(appName)
      .config("spark.sql.warehouse.dir", "/user/hive/warehouse")
      .config("spark.sql.adaptive.enabled", "true")
      .config("spark.sql.adaptive.coalescePartitions.enabled", "true")
      .config("spark.sql.broadcastTimeout", "600")
      .config("spark.network.timeout", "600s")
      .config("spark.executor.heartbeatInterval", "60s")
      .enableHiveSupport()
      .getOrCreate()
  }
  
  def registerDataLakeTables(spark: SparkSession, dataLakePath: String): Unit = {
    spark.sql(s"""
      CREATE TABLE IF NOT EXISTS sales_data (
        sale_id STRING,
        customer_id STRING,
        product_id STRING,
        quantity INT,
        price DOUBLE,
        sale_date DATE,
        region STRING
      )
      USING parquet
      LOCATION '$dataLakePath/sales_data'
    """)
    
    spark.sql(s"""
      CREATE TABLE IF NOT EXISTS customer_data (
        customer_id STRING,
        name STRING,
        email STRING,
        registration_date DATE,
        country STRING,
        lifetime_value DOUBLE
      )
      USING parquet
      LOCATION '$dataLakePath/customer_data'
    """)
    
    spark.sql(s"""
      CREATE TABLE IF NOT EXISTS product_catalog (
        product_id STRING,
        product_name STRING,
        category STRING,
        subcategory STRING,
        price DOUBLE,
        cost DOUBLE,
        supplier STRING
      )
      USING parquet
      LOCATION '$dataLakePath/product_catalog'
    """)
    
    spark.sql(s"""
      CREATE TABLE IF NOT EXISTS web_analytics (
        session_id STRING,
        user_id STRING,
        page_url STRING,
        timestamp TIMESTAMP,
        duration_seconds INT,
        device_type STRING,
        referrer STRING
      )
      USING parquet
      LOCATION '$dataLakePath/web_analytics'
    """)
    
    spark.sql(s"""
      CREATE TABLE IF NOT EXISTS transaction_logs (
        transaction_id STRING,
        user_id STRING,
        transaction_type STRING,
        amount DOUBLE,
        currency STRING,
        status STRING,
        timestamp TIMESTAMP
      )
      USING parquet
      LOCATION '$dataLakePath/transaction_logs'
    """)
    
    spark.sql(s"""
      CREATE TABLE IF NOT EXISTS user_events (
        event_id STRING,
        user_id STRING,
        event_type STRING,
        event_data STRING,
        timestamp TIMESTAMP,
        platform STRING
      )
      USING parquet
      LOCATION '$dataLakePath/user_events'
    """)
  }
  
  def main(args: Array[String]): Unit = {
    val spark = initializeSpark("DataLakeAnalytics")
    
    val dataLakePath = if (args.length > 0) args(0) else "/datalake"
    registerDataLakeTables(spark, dataLakePath)
    
    val queryExecutor = new SecureQueryExecutor(spark)
    
    val exampleQueries = List(
      QueryRequest(
        query = """
          SELECT 
            region,
            COUNT(*) as total_sales,
            SUM(quantity * price) as total_revenue,
            AVG(price) as avg_price
          FROM sales_data
          WHERE sale_date >= '2024-01-01'
          GROUP BY region
          ORDER BY total_revenue DESC
        """,
        maxRows = Some(100)
      ),
      QueryRequest(
        query = """
          SELECT 
            c.country,
            COUNT(DISTINCT c.customer_id) as customer_count,
            SUM(s.quantity * s.price) as total_spent
          FROM customer_data c
          JOIN sales_data s ON c.customer_id = s.customer_id
          GROUP BY c.country
          HAVING total_spent > 10000
        """,
        maxRows = Some(50)
      ),
      QueryRequest(
        query = """
          WITH monthly_sales AS (
            SELECT 
              DATE_TRUNC('month', sale_date) as month,
              product_id,
              SUM(quantity) as units_sold
            FROM sales_data
            GROUP BY DATE_TRUNC('month', sale_date), product_id
          )
          SELECT 
            p.product_name,
            p.category,
            ms.month,
            ms.units_sold
          FROM monthly_sales ms
          JOIN product_catalog p ON ms.product_id = p.product_id
          ORDER BY ms.month DESC, ms.units_sold DESC
        """,
        maxRows = Some(200)
      )
    )
    
    println("Executing example queries...")
    exampleQueries.zipWithIndex.foreach { case (request, idx) =>
      println(s"\n=== Query ${idx + 1} ===")
      println(s"SQL: ${request.query.take(100)}...")
      
      val result = queryExecutor.executeQueryWithTimeout(request)
      
      if (result.success) {
        println(s"✓ Success - ${result.rowCount.getOrElse(0)} rows, ${result.executionTimeMs}ms")
        result.schema.foreach(schema => println(s"Schema: ${schema.mkString(", ")}"))
      } else {
        println(s"✗ Failed: ${result.error.getOrElse("Unknown error")}")
      }
    }
    
